args.sparql:
SELECT ?team ?teamLabel ?losses WHERE {
  ?team wdt:P5204 wd:Q341461 .
  ?team wdt:P2131 ?losses .
  ?team rdfs:label ?teamLabel .
  FILTER (lang(?teamLabel) = "en")
} order by desc(?losses) limit 1

SELECT ?team ?teamLabel ?losses WHERE {
  ?team wdt:P5204 wd:Q341461 .
  ?team wdt:P320 ?losses .
  ?team rdfs:label ?teamLabel .
  FILTER (lang(?teamLabel) = "en")
} ORDER BY DESC(?losses) LIMIT 1
